/**
 * POST /api/events/[eventId]/scan-results
 *
 * Accepts a batch of offline scan results from a local scanner node.
 * Each result contains: identifier (rfidEpc or barcodeNumber), outcome,
 * timestamp, and optional node metadata.
 *
 * Results are stored in the ScanLog table (created below if not exists — see schema note).
 * Protected by bearer scanner token OR admin session cookie.
 */

import { NextResponse } from "next/server";
import { cookies } from "next/headers";
import { prisma } from "@/lib/prisma";

export interface OfflineScanResult {
  /** Unique ID generated by local node for idempotency */
  localId: string;
  scanMode: "RFID" | "BARCODE";
  identifier: string;          // rfidEpc or barcodeNumber
  outcome: "GREEN" | "RED" | "YELLOW";
  reason: string;
  tireId?: string;
  registrationId?: string;
  scannedAt: string;           // ISO8601 timestamp from local node clock
  nodeId?: string;             // Identifier for the physical scanner node
  nodeName?: string;
}

function authorise(request: Request, userData: string | undefined): boolean {
  const auth = request.headers.get("authorization") ?? "";
  if (auth.startsWith("Bearer ")) {
    const token = auth.slice(7);
    const expected = process.env.SCANNER_NODE_SECRET;
    if (expected && token === expected) return true;
  }
  if (userData) {
    const user = JSON.parse(userData);
    const allowed = ["SUPERADMIN", "CLUBADMIN", "FEDERATION_ADMIN",
      "TECHNICAL_INSPECTOR", "RACE_OFFICIAL", "WEIGHT_CONTROLLER"];
    return allowed.includes(user.role);
  }
  return false;
}

export async function POST(
  request: Request,
  { params }: { params: Promise<{ eventId: string }> }
) {
  try {
    const cookieStore = await cookies();
    const userData = cookieStore.get("user")?.value;
    if (!authorise(request, userData)) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { eventId } = await params;

    const event = await prisma.event.findUnique({ where: { id: eventId }, select: { id: true } });
    if (!event) return NextResponse.json({ error: "Event ikke funnet" }, { status: 404 });

    const body = await request.json();
    const results: OfflineScanResult[] = Array.isArray(body) ? body : body.results;

    if (!results || results.length === 0) {
      return NextResponse.json({ error: "Ingen resultater i batch" }, { status: 400 });
    }
    if (results.length > 5000) {
      return NextResponse.json({ error: "Maks 5000 resultater per batch" }, { status: 400 });
    }

    // Upsert using localId for idempotency — safe to re-send same batch
    const created: string[] = [];
    const skipped: string[] = [];

    for (const r of results) {
      if (!r.localId || !r.identifier || !r.outcome || !r.scannedAt) {
        skipped.push(r.localId ?? "(ukjent)");
        continue;
      }
      try {
        await prisma.scanLog.upsert({
          where: { localId: r.localId },
          create: {
            localId: r.localId,
            eventId,
            scanMode: r.scanMode ?? "RFID",
            identifier: r.identifier,
            outcome: r.outcome,
            reason: r.reason ?? "",
            tireId: r.tireId ?? null,
            registrationId: r.registrationId ?? null,
            scannedAt: new Date(r.scannedAt),
            nodeId: r.nodeId ?? null,
            nodeName: r.nodeName ?? null,
          },
          update: {},  // Never overwrite — idempotent
        });
        created.push(r.localId);
      } catch {
        skipped.push(r.localId);
      }
    }

    return NextResponse.json({
      accepted: created.length,
      skipped: skipped.length,
      skippedIds: skipped,
      eventId,
      syncedAt: new Date().toISOString(),
    });
  } catch {
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

/** GET — retrieve scan log for an event (for admin review) */
export async function GET(
  request: Request,
  { params }: { params: Promise<{ eventId: string }> }
) {
  try {
    const cookieStore = await cookies();
    const userData = cookieStore.get("user")?.value;
    if (!userData) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    const user = JSON.parse(userData);
    const allowed = ["SUPERADMIN", "CLUBADMIN", "FEDERATION_ADMIN",
      "TECHNICAL_INSPECTOR", "RACE_OFFICIAL"];
    if (!allowed.includes(user.role)) {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 });
    }

    const { eventId } = await params;
    const { searchParams } = new URL(request.url);
    const outcome = searchParams.get("outcome");
    const nodeId = searchParams.get("nodeId");
    const limit = Math.min(parseInt(searchParams.get("limit") ?? "200"), 1000);

    const logs = await prisma.scanLog.findMany({
      where: {
        eventId,
        ...(outcome ? { outcome: outcome as any } : {}),
        ...(nodeId ? { nodeId } : {}),
      },
      orderBy: { scannedAt: "desc" },
      take: limit,
      include: {
        tire: {
          select: {
            rfidEpc: true, barcodeNumber: true,
            approvedTire: { select: { manufacturer: true, model: true, size: true } },
            currentOwner: { select: { name: true, email: true } },
          },
        },
      },
    });

    return NextResponse.json(logs);
  } catch {
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}
